import{_ as a,o as t,c as o,a2 as r}from"./chunks/framework.DGp-bpT-.js";const p=JSON.parse('{"title":"Общение с ботом и правила взаимодействия","description":"","frontmatter":{},"headers":[],"relativePath":"guide/interaction.md","filePath":"guide/interaction.md","lastUpdated":null}'),i={name:"guide/interaction.md"};function l(n,e,s,d,c,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="общение-с-ботом-и-правила-взаимодеиствия" tabindex="-1">Общение с ботом и правила взаимодействия <a class="header-anchor" href="#общение-с-ботом-и-правила-взаимодеиствия" aria-label="Permalink to &quot;Общение с ботом и правила взаимодействия&quot;">​</a></h1><p>Платформа SREBot позволяет не только получать автоматический анализ алертов (RCA), но и вести диалог с ботом в чате для уточнения деталей.</p><h2 id="как-задать-уточняющии-вопрос" tabindex="-1">Как задать уточняющий вопрос <a class="header-anchor" href="#как-задать-уточняющии-вопрос" aria-label="Permalink to &quot;Как задать уточняющий вопрос&quot;">​</a></h2><p>Чтобы задать вопрос боту по поводу конкретного инцидента:</p><ol><li>Найдите сообщение бота с анализом (RCA) в Telegram-канале или чате.</li><li>Ответьте на это сообщение (<strong>Reply</strong>) своим вопросом.</li><li>Бот увидит ваш ответ, покажет статус «Анализирую...» и пришлет уточненную информацию.</li></ol><h2 id="правила-общения-с-ботом" tabindex="-1">Правила общения с ботом <a class="header-anchor" href="#правила-общения-с-ботом" aria-label="Permalink to &quot;Правила общения с ботом&quot;">​</a></h2><p>Чтобы бот работал эффективно и не тратил ваши токены впустую, соблюдайте следующие правила:</p><h3 id="_1-тематика-вопросов" tabindex="-1">1. Тематика вопросов <a class="header-anchor" href="#_1-тематика-вопросов" aria-label="Permalink to &quot;1. Тематика вопросов&quot;">​</a></h3><p>Бот спроектирован как профессиональный SRE-ассистент. Он отвечает <strong>только на вопросы, связанные с текущим инцидентом</strong>, предоставленным анализом или общими задачами диагностики и обсервабилити.</p><p><strong>Примеры хороших вопросов:</strong></p><ul><li><em>«Покажи логи за последние 10 минут с этой ноды»</em></li><li><em>«Какая загрузка CPU была в момент алерта?»</em></li><li><em>«Какие еще алерты срабатывали в этом кластере за час?»</em></li></ul><p><strong>Защита от оффтопа:</strong> Если вы спросите бота о чем-то, не связанном с инцидентом (например, <em>«расскажи анекдот»</em> или <em>«как дела»</em>), бот вежливо откажется отвечать, чтобы сберечь баланс токенов вашей организации.</p><h3 id="_2-язык-общения" tabindex="-1">2. Язык общения <a class="header-anchor" href="#_2-язык-общения" aria-label="Permalink to &quot;2. Язык общения&quot;">​</a></h3><p>Бот может общаться на разных языках. Язык ответов настраивается в панели управления или через переменную окружения <code>LLM_RESPONSE_LANGUAGE</code>. Если вы хотите, чтобы бот отвечал на русском, убедитесь, что этот параметр установлен в <code>Russian</code>.</p><h3 id="_3-ограничения-лимиты" tabindex="-1">3. Ограничения (Лимиты) <a class="header-anchor" href="#_3-ограничения-лимиты" aria-label="Permalink to &quot;3. Ограничения (Лимиты)&quot;">​</a></h3><p>Для защиты от бесконечных циклов и спама действуют следующие ограничения:</p><ul><li><strong>Кулдаун</strong>: между вопросами одного пользователя должна быть пауза (по умолчанию 5 секунд).</li><li><strong>Максимум вопросов</strong>: на один инцидент можно задать ограниченное количество вопросов (по умолчанию 5). При превышении лимита бот сообщит, что лимит исчерпан.</li></ul><p>Эти параметры настраиваются на стороне бота (<code>FOLLOWUP_COOLDOWN</code>, <code>FOLLOWUP_MAX_TURNS</code>).</p>',18)])])}const m=a(i,[["render",l]]);export{p as __pageData,m as default};
